// Parse LLM classification response, validate category, fallback to "other"

const VALID_CATEGORIES = [
  'modify_infrastructure',
  'incident',
  'question',
  'ci_cd_error',
  'limits',
  'new_system',
  'announcement',
  'other'
];

const aiOutput = $input.first().json.text || $input.first().json.output || '';

let parsed;
try {
  const clean = aiOutput.replace(/```json\s*|```\s*/g, '').trim();
  // Extract the first {...} block to survive any stray prose from tool turns
  const match = clean.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : JSON.parse(clean);
} catch (e) {
  parsed = { category: 'other', confidence: 0, summary: 'Failed to parse AI response', acknowledge: '' };
}

if (!VALID_CATEGORIES.includes(parsed.category)) {
  parsed.category = 'other';
  parsed.confidence = 0;
}

// Merge with upstream data, exclude base64 attachments to save memory
const upstream = $('Router').first().json;
const { attachments, ...upstreamClean } = upstream;

return [{
  json: {
    ...upstreamClean,
    category: parsed.category,
    confidence: parsed.confidence,
    summary: parsed.summary || '',
    acknowledge: parsed.acknowledge || ''
  }
}];

// Parse Slack app_mention event and extract clean message
const headers = $input.first().json.headers;
const body = $input.first().json.body;

// Validate Slack verification token
const SLACK_TOKEN = $input.first().json.CHAT_TOKEN;
if (body.token !== SLACK_TOKEN) {
  throw new Error('Invalid Slack verification token');
}

// Skip Slack retries (Slack retries if no 200 within 3s)
if (headers['x-slack-retry-num']) {
  return [];
}

// URL verification (should not happen after initial setup, but just in case)
if (body.type === 'url_verification') {
  return [{
    json: {
      isChallenge: true,
      challenge: body.challenge
    }
  }];
}

const event = body.event || {};

// Strip <@UXXXXX> bot mention and clean whitespace
const cleanText = (event.text || '')
  .replace(/<@[A-Z0-9]+>\s*/g, '')
  .trim();

// Reject empty messages
if (!cleanText) {
  return [];
}
const isInThread = Boolean(event.thread_ts) && event.thread_ts !== event.ts;
// Slack puts uploaded files into event.files (present for message and app_mention events when files are attached).
const files = Array.isArray(event.files) ? event.files : [];
const fileIds = files.map(f => f && f.id).filter(Boolean);
return [{
  json: {
    isChallenge: false,
    message: cleanText,
    user_id: event.user,
    channel_id: event.channel,
    ts: event.ts,
    thread_ts: event.thread_ts || event.ts,
    is_in_thread: isInThread,
    team_id: body.team_id,
    event_type: event.type,
    file_ids: fileIds
  }
}];

