const profile = $input.first().json;

const userName =
  profile.real_name ||
  profile.display_name ||
  profile.real_name_normalized ||
  profile.display_name_normalized ||
  '';

return [{
  json: {
    ...upstream,
    user_name: userName,
  },
}];
